const records = $input.all();
let totalSignals = 0;
let positiveSignals = 0;
let negativeSignals = 0;

for (const record of records) {
  totalSignals += Number(record.json.fields.total_signals || 0);
  positiveSignals += Number(record.json.fields.positive_signals || 0);
  negativeSignals += Number(record.json.fields.negative_signals || 0);
}

const positiveRate = totalSignals > 0 ? Number((positiveSignals / totalSignals).toFixed(2)) : 0;
const negativeRate = totalSignals > 0 ? Number((negativeSignals / totalSignals).toFixed(2)) : 0;

return [{
  json: {
    total_signals: totalSignals,
    positive_signals: positiveSignals,
    negative_signals: negativeSignals,
    positive_rate: positiveRate,
    negative_rate: negativeRate
  }
}];

const metrics = $input.first().json;
let summary = 'Not enough feedback yet to make a prompt change.';
const recommendations = [];

if (metrics.negative_rate >= 0.4) {
  summary = 'High negative feedback detected. Tighten prompts to reduce noisy findings.';
  recommendations.push({ area: 'all_reviewers', action: 'reduce low-confidence findings' });
}

if (metrics.positive_rate >= 0.75) {
  recommendations.push({ area: 'security_reviewer', action: 'keep current security prompt stable' });
}

if (metrics.positive_rate < 0.6) {
  recommendations.push({ area: 'style_reviewer', action: 'review style prompt for relevance and precision' });
}

return [{
  json: {
    recommendation_summary: summary,
    recommendations_json: JSON.stringify(recommendations)
  }
}];

